{
    Console.WriteLine($"Resolved UnknownType: {missing!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<UnknownType> returned false — no exception thrown.");
}

// Types
public record Person(string Name, int Age);
public record UnknownType(string Value);

// A source-gen context that only resolves Person
[JsonSerializable(typeof(Person))]
internal partial class LimitedContext : JsonSerializerContext { }
EOF
